unordered_map<int, vector<int>> buildGraph(vector<pair<int,int>>& edges) {
    unordered_map<int, vector<int>> g;
    for (auto& [u, v] : edges) {
        g[u].push_back(v);
        g[v].push_back(u);
    }
    return g;
}
